package com.DecisionMakingStatements;

public class Switch {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num = 1;
		
		switch (num) {
		
		case 0:
			System.out.println("number is 0:Coforge");
			break;
		case 1:
			System.out.println("number is 1:Arpita");
			break;
		case 2:
			System.out.println("number is 2:Das");
			break;
		case 3:
			System.out.println("number is 3:Odisha");
			break;	
		default:
			System.out.println(num);
			
		}

	}

}
